parameters.inputSchema:
{
  "$schema": "https://json-schema.org/draft/2020-12/schema",
  "type": "object",
  "properties": {
    "category_id": {
      "type": "string",
      "description": "UUID v4 identificador de la categoría",
      "pattern": "^[0-9a-fA-F]{8}-[0-9a-fA-F]{4}-4[0-9a-fA-F]{3}-[89abAB][0-9a-fA-F]{3}-[0-9a-fA-F]{12}$"
    },
    "tags": {
      "type": "array",
      "items": {
        "type": "string"
      },
      "description":  "Una lista de mínimo 3 tags relevantes según el contenido, sugiere si es necesario basado en el comercio, primer nombre de persona, gasto, delivery, etc. LOWER CASE siempre, solo una palabra por tag."
    },
    "account_id": {
      "type": "string",
      "description": "UUID v4 identificador de la cuenta",
      "pattern": "^[0-9a-fA-F]{8}-[0-9a-fA-F]{4}-4[0-9a-fA-F]{3}-[89abAB][0-9a-fA-F]{3}-[0-9a-fA-F]{12}$"
    },
    "description": {
      "type": "string",
      "description": "Descripción de la transacción"
    },
    "amount": {
      "type": "number",
      "description": "Monto de la transacción. Negativo para egresos"
    },
    "created_at": {
      "type": "string",
      "format": "date-time",
      "description": "Fecha y hora de la transacción en formato ISO 8601"
    },
    "currency": {
      "type": "string",
      "pattern": "^[A-Z]{3}$",
      "description": "Código de moneda en formato ISO 4217 (ej. PEN, USD)"
    }
  },
  "required": [
    "category_id",
    "tags",
    "account_id",
    "description",
    "amount",
    "created_at",
    "currency"
  ],
  "additionalProperties": false
}

